import{_ as o,y as g,a as u,o as r,ag as i,D as a,g as t,I as c}from"./chunks/framework.RVu0gECZ.js";const b=JSON.parse('{"title":"Quy tắc Danh mục","description":"","frontmatter":{},"headers":[],"relativePath":"marketing/catalog-rules.md","filePath":"marketing/catalog-rules.md","lastUpdated":1775325006000}'),s={name:"marketing/catalog-rules.md"};function p(m,n,e,l,d,y){const h=g("ImagePopup");return r(),u("div",null,[n[0]||(n[0]=i('<h1 id="quy-tac-danh-muc" tabindex="-1">Quy tắc Danh mục <a class="header-anchor" href="#quy-tac-danh-muc" aria-label="Permalink to &quot;Quy tắc Danh mục&quot;">​</a></h1><p>Quy tắc danh mục là một quy tắc đặc biệt cho phép khách hàng mua sản phẩm với mức giá chiết khấu do quản trị viên đặt từ chương trình phụ trợ. Ở đây sẽ thảo luận về cách thiết lập quy tắc danh mục trong VNS.</p><p>Quy tắc danh mục được áp dụng cho sản phẩm trước khi đưa vào giỏ hàng. Thực hiện theo bước bên dưới “Cách đặt quy tắc danh mục trong VNS”.</p><h3 id="buoc-1-them-quy-tac-danh-muc-moi" tabindex="-1">Bước 1: Thêm Quy tắc Danh mục Mới <a class="header-anchor" href="#buoc-1-them-quy-tac-danh-muc-moi" aria-label="Permalink to &quot;Bước 1: Thêm Quy tắc Danh mục Mới&quot;">​</a></h3><p>a) Trên bảng Quản trị, đi tới <strong>Tiếp thị &gt;&gt; Khuyến mãi &gt;&gt; Quy tắc danh mục</strong></p><p>b) Ở phía trên bên phải, nhấp vào nút <strong>Tạo quy tắc danh mục</strong> như hiển thị bên dưới</p>',6)),a(h,{src:"/images/marketing/catalogRule.png",alt:"Catalog"}),n[1]||(n[1]=i('<h3 id="thuc-hien-nhap-noi-dung-sau-vao-muc-thong-tin-quy-tac" tabindex="-1">Thực hiện nhập nội dung sau vào Mục Thông tin Quy tắc <a class="header-anchor" href="#thuc-hien-nhap-noi-dung-sau-vao-muc-thong-tin-quy-tac" aria-label="Permalink to &quot;Thực hiện nhập nội dung sau vào Mục Thông tin Quy tắc&quot;">​</a></h3><p><strong>1. Tên:-</strong> Nhập tên của quy tắc danh mục mới. (chỉ mang tính chất tham khảo nội bộ)</p><p><strong>2. Mô tả:-</strong> Nhập mô tả của quy tắc. (chỉ mang tính chất tham khảo nội bộ)</p><p><strong>3. Trạng thái:-</strong> Đặt trạng thái của quy tắc danh mục đang hoạt động.</p><p><strong>4. Kênh:-</strong> Chọn kênh mà quy tắc danh mục này sẽ được áp dụng.</p><p><strong>5. Nhóm khách hàng:-</strong> Chọn nhóm khách hàng sẽ áp dụng quy tắc danh mục này.</p><p><strong>6. Ngày từ và đến:-</strong> Đặt phạm vi ngày mà quy tắc danh mục sẽ bị ảnh hưởng. Nếu bạn không đặt ngày, quy tắc sẽ được áp dụng ngay khi quy tắc được lưu.</p><p><strong>7. Mức độ ưu tiên:-</strong> Nhập mức độ ưu tiên của quy tắc này.</p>',8)),a(h,{src:"/images/marketing/catalogConfigurations.png",alt:"Catalog Configurations"}),n[2]||(n[2]=t("h3",{id:"buoc-2-đat-đieu-kien",tabindex:"-1"},[c("Bước 2: Đặt điều kiện "),t("a",{class:"header-anchor",href:"#buoc-2-đat-đieu-kien","aria-label":'Permalink to "Bước 2: Đặt điều kiện"'},"​")],-1)),n[3]||(n[3]=t("p",null,"Tất cả điều kiện trong quy tắc danh mục đều dựa trên thuộc tính sản phẩm. Nếu bạn muốn áp dụng quy tắc cho tất cả các sản phẩm, đừng đặt bất kỳ điều kiện nào. Đặt loại điều kiện thành tất cả các điều kiện đúng hoặc bất kỳ điều kiện nào đúng.",-1)),a(h,{src:"/images/marketing/condition.png",alt:"Condition"}),n[4]||(n[4]=t("p",null,"Sau đó click vào Add condition để thiết lập điều kiện. Trong danh sách thuộc tính sản phẩm, chọn thuộc tính bạn muốn đặt cho điều kiện.",-1)),a(h,{src:"/images/marketing/catalogConditions.png",alt:"Conditions"}),n[5]||(n[5]=t("p",null,"Ví dụ: nếu bạn đã chọn Danh mục thì bạn phải chọn chứa/không chứa và chọn danh mục như trong hình bên dưới.",-1)),n[6]||(n[6]=t("p",null,"Nếu muốn xóa điều kiện nào thì nhấn vào biểu tượng xóa.",-1)),a(h,{src:"/images/marketing/contains.png",alt:"Contains"}),n[7]||(n[7]=t("h3",{id:"buoc-3-thiet-lap-hanh-đong",tabindex:"-1"},[c("Bước 3: Thiết lập hành động "),t("a",{class:"header-anchor",href:"#buoc-3-thiet-lap-hanh-đong","aria-label":'Permalink to "Bước 3: Thiết lập hành động"'},"​")],-1)),n[8]||(n[8]=t("p",null,"Trong phần Hành động, chúng ta phải đặt các hành động như cách chúng ta muốn áp dụng quy tắc cho sản phẩm.",-1)),a(h,{src:"/images/marketing/catalogAction.png",alt:"Catalog Action"}),n[9]||(n[9]=i("<p><strong>1. Loại hành động:-</strong> Bạn có thể áp dụng giảm giá theo tỷ lệ phần trăm hoặc số tiền cố định.</p><p><strong>2. Số tiền giảm giá:-</strong> Nhập số tiền giảm giá.</p><p><strong>3. Kết thúc các quy tắc khác:-</strong> Để ngừng áp dụng các quy tắc khác sau khi áp dụng quy tắc này, hãy đặt “Có”. Điều này sẽ có tác dụng khi áp dụng nhiều mức giảm giá cho cùng một sản phẩm.</p><p><strong>Lưu ý: - Nếu bạn muốn áp dụng nhiều quy tắc cho sản phẩm thì hãy đặt “KHÔNG”. Vì vậy, trong trường hợp đó, quy tắc có mức độ ưu tiên cao nhất sẽ được áp dụng trước.</strong></p><p>Bây giờ <strong>Lưu Quy tắc danh mục</strong> và bạn sẽ có thể thấy <strong>Quy tắc danh mục</strong> mới đã được tạo thành công.</p>",5)),a(h,{src:"/images/marketing/catalogOutput.png",alt:"Catalog Output"}),n[10]||(n[10]=t("h3",{id:"phan-đau",tabindex:"-1"},[c("Phần đầu:- "),t("a",{class:"header-anchor",href:"#phan-đau","aria-label":'Permalink to "Phần đầu:-"'},"​")],-1)),n[11]||(n[11]=t("p",null,"Bạn sẽ được GIẢM GIÁ 50% cho sản phẩm sau khi áp dụng quy tắc danh mục như dưới đây.",-1)),a(h,{src:"/images/marketing/catalogFront.png",alt:"Catalog Front"}),n[12]||(n[12]=t("p",null,[c("Bằng cách này, bạn có thể dễ dàng tạo "),t("strong",null,"Quy tắc danh mục"),c(" trong VNS.")],-1))])}const T=o(s,[["render",p]]);export{b as __pageData,T as default};
